#!/usr/bin/env bash
# Run trigger-accuracy optimization for Logic-Lens skills via skill-creator's run_loop.py.
#
# Prerequisites:
#   - skill-creator plugin installed; default cache path is
#     ~/.claude/plugins/marketplaces/anthropic-agent-skills/skills/skill-creator
#     Override with SKILL_CREATOR_PATH=... if the plugin lives elsewhere.
#   - `claude` CLI on PATH.
#   - Trigger eval JSON files sit in evals/trigger/v2/trigger-evals-<skill>.json
#     (6 files, 20 cases each, generated by the v0.4 evaluation pass).
#
# Usage:
#   bash scripts/run-trigger-evals.sh            # all 6 skills
#   bash scripts/run-trigger-evals.sh review     # one skill
#   MAX_ITERATIONS=3 bash scripts/run-trigger-evals.sh  # shorter loop
#
# Each run invokes run_loop.py which:
#   1. Splits the 20 items into 60% train / 40% held-out test
#   2. Evaluates the current SKILL.md description three times per query
#      for a stable trigger rate
#   3. Asks Claude (with extended thinking) to propose improved descriptions
#      for the cases that failed, up to MAX_ITERATIONS rounds
#   4. Selects the best description by held-out test score and opens an
#      HTML report in the default browser
#
# Output: JSON to stdout with best_description. Apply it by editing the
# corresponding skills/logic-<skill>/SKILL.md frontmatter description field.
set -euo pipefail

REPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
SKILL_CREATOR_PATH="${SKILL_CREATOR_PATH:-$HOME/.claude/plugins/marketplaces/anthropic-agent-skills/skills/skill-creator}"
MAX_ITERATIONS="${MAX_ITERATIONS:-5}"
REPORT="${REPORT:-none}"
# shellcheck source=_defaults.sh
source "$(dirname "${BASH_SOURCE[0]}")/_defaults.sh"

if ! [[ "$MAX_ITERATIONS" =~ ^[1-9][0-9]*$ ]]; then
  echo "ERROR: MAX_ITERATIONS must be a positive integer (got '$MAX_ITERATIONS')." >&2
  exit 1
fi

if [[ ! -f "$SKILL_CREATOR_PATH/scripts/run_loop.py" ]]; then
  echo "ERROR: skill-creator run_loop.py not found at $SKILL_CREATOR_PATH/scripts/run_loop.py" >&2
  echo "Set SKILL_CREATOR_PATH env var to the correct skill-creator directory." >&2
  exit 1
fi

run_skill() {
  local skill="$1"
  local eval_file=""
  local legacy_eval_file="$REPO_ROOT/evals/v2/trigger-evals-${skill}.json"
  local new_eval_file="$REPO_ROOT/evals/trigger/v2/trigger-evals-${skill}.json"
  for candidate in \
    "$new_eval_file" \
    "$legacy_eval_file"; do
    if [[ -f "$candidate" ]]; then
      eval_file="$candidate"
      break
    fi
  done
  local skill_path="$REPO_ROOT/skills/logic-${skill}"
  if [[ -z "$eval_file" ]]; then
    echo "SKIP: no eval file for '$skill' at $new_eval_file or $legacy_eval_file" >&2
    return 0
  fi
  echo "=== logic-${skill} trigger optimization ==="
  PYTHONPATH="$SKILL_CREATOR_PATH${PYTHONPATH:+:$PYTHONPATH}" \
  python3 "$SKILL_CREATOR_PATH/scripts/run_loop.py" \
    --eval-set "$eval_file" \
    --skill-path "$skill_path" \
    --model "$MODEL" \
    --max-iterations "$MAX_ITERATIONS" \
    --report "$REPORT" \
    --verbose
  echo
}

if [[ $# -eq 0 ]]; then
  for skill in review explain diff locate health fix-all; do
    run_skill "$skill"
  done
else
  for skill in "$@"; do
    run_skill "$skill"
  done
fi
